"""
Parameterized generator for GH1182_mlflow_21810.

Source PR:    https://github.com/mlflow/mlflow/pull/21810
Source Issue: N/A

Seed varies: renames 'additional' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1182_mlflow_21810'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1182_mlflow_21810'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('additional', 'additional' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1182_mlflow_21810',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'mlflow/mlflow',
                "pr_number": 21810,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/mlflow/mlflow/pull/21810",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'mlflow/llama_index/tracer.py': 'import inspect\nimport json\nimport logging\nfrom functools import singledispatchmethod\nfrom typing import Any, Generator\n\nimport llama_index.core\nimport pydantic\nfrom llama_index.core.base.base_retriever import BaseRetriever\nfrom llama_index.core.base.embeddings.base import BaseEmbedding\nfrom llama_index.core.base.llms.base import BaseLLM\nfrom llama_index.core.base.llms.types import ChatResponse, CompletionResponse\nfrom llama_index.core.base.response.schema import AsyncStreamingResponse, StreamingResponse\nfrom llama_index.core.chat_engine.types import StreamingAgentChatResponse\nfrom llama_index.core.instrumentation.event_handlers import BaseEventHandler\nfrom llama_index.core.instrumentation.events import BaseEvent\nfrom llama_index.core.instrumentation.events.agent import AgentToolCallEvent\nfrom llama_index.core.instrumentation.events.embedding import EmbeddingStartEvent\nfrom llama_index.core.instrumentation.events.exception import ExceptionEvent\nfrom llama_index.core.instrumentation.events.llm import (\n    LLMChatEndEvent,\n    LLMChatStartEvent,\n    LLMCompletionEndEvent,\n    LLMCompletionStartEvent,\n    LLMPredictStartEvent,\n)\nfrom llama_index.core.instrumentation.events.rerank import ReRankStartEvent\nfrom llama_index.core.instrumentation.span.base import BaseSpan\nfrom llama_index.core.instrumentation.span_handlers import BaseSpanHandler\nfrom llama_index.core.multi_modal_llms import MultiModalLLM\nfrom llama_index.core.schema import NodeWithScore\nfrom llama_index.core.tools import BaseTool\nfrom packaging.version import Version\n\nimport mlflow\nfrom mlflow.entities import LiveSpan, SpanEvent, SpanType\nfrom mlflow.entities.document import Document\nfrom mlflow.entities.span_status import SpanStatusCode\nfrom mlflow.tracing.constant import SpanAttributeKey, TokenUsageKey\nfrom mlflow.tracing.fluent import start_span_no_context\nfrom mlflow.tracing.provider import detach_span_from_context, set_span_in_context\nfrom mlflow.tracing.utils import set_span_chat_tools\n\n_logger = logging.getLogger(__name__)\n\n\ndef _get_llama_index_version() -> Version:\n    return Version(llama_index.core.__version__)\n\n\ndef set_llama_index_tracer():\n    """\n    Set the MlflowSpanHandler and MlflowEventHandler to the global dispatcher.\n    If the handlers are already set, skip setting.\n    """\n    from llama_index.core.instrumentation import get_dispatcher\n\n    dsp = get_dispatcher()\n    span_handler = None\n    for handler in dsp.span_handlers:\n        if isinstance(handler, MlflowSpanHandler):\n            _logger.debug("MlflowSpanHandler is already set to the dispatcher. Skip setting.")\n            span_handler = handler\n            break\n    else:\n        span_handler = MlflowSpanHandler()\n        dsp.add_span_handler(span_handler)\n\n    for handler in dsp.event_handlers:\n        if isinstance(handler, MlflowEventHandler):\n            _logger.debug("MlflowEventHandler is already set to the dispatcher. Skip setting.")\n            break\n    else:\n        dsp.add_event_handler(MlflowEventHandler(span_handler))\n\n\ndef remove_llama_index_tracer():\n    """\n    Remove the MlflowSpanHandler and MlflowEventHandler from the global dispatcher.\n    """\n    from llama_index.core.instrumentation import get_dispatcher\n\n    dsp = get_dispatcher()\n    dsp.span_handlers = [h for h in dsp.span_handlers if h.class_name() != "MlflowSpanHandler"]\n    dsp.event_handlers = [h for h in dsp.event_handlers if h.class_name() != "MlflowEventHandler"]\n\n\nclass _LlamaSpan(BaseSpan, extra="allow"):\n    _mlflow_span: LiveSpan = pydantic.PrivateAttr()\n\n    def __init__(self, id_: str, parent_id: str | None, mlflow_span: LiveSpan):\n        super().__init__(id_=id_, parent_id=parent_id)\n        self._mlflow_span = mlflow_span\n\n\ndef _end_span(span: LiveSpan, status=SpanStatusCode.OK, outputs=None, token=None):\n    """An utility function to end the span or trace."""\n    if isinstance(outputs, (StreamingResponse, AsyncStreamingResponse, StreamingAgentChatResponse)):\n        _logger.warning(\n            "Trying to record streaming response to the MLflow trace. This may consume "\n            "the generator and result in an empty response."\n        )\n\n    # for retriever spans, convert the outputs to Document objects\n    # so they can be rendered in a more user-friendly way in the UI\n    if (\n        span.span_type == SpanType.RETRIEVER\n        and isinstance(outputs, list)\n        and all(isinstance(item, NodeWithScore) for item in outputs)\n    ):\n        try:\n            outputs = [Document.from_llama_index_node_with_score(node) for node in outputs]\n        except Exception as e:\n            _logger.debug(\n                f"Failed to convert NodeWithScore to Document objects: {e}", exc_info=True\n            )\n\n    if outputs is None:\n        outputs = span.outputs\n\n    try:\n        span.end(status=status, outputs=outputs)\n    finally:\n        # We should detach span even when end_span / end_trace API call fails\n        if token:\n            detach_span_from_context(token)\n\n\ndef _is_workflow_handler(result):\n    """Check if the result is a WorkflowHandler from llama-index-workflows >= 2.0."""\n    try:\n        from workflows.handler import WorkflowHandler\n\n        return isinstance(result, WorkflowHandler)\n    except (ImportError, ModuleNotFoundError):\n        return False\n\n\nclass MlflowSpanHandler(BaseSpanHandler[_LlamaSpan], extra="allow"):\n    def __init__(self):\n        super().__init__()\n        self._span_id_to_token = {}\n        self._stream_resolver = StreamResolver()\n        self._pending_spans: dict[str, _LlamaSpan] = {}\n        # Track workflow spans that are pending completion (WorkflowHandler returned)\n        self._pending_workflow_span_ids: set[str] = set()\n\n    @classmethod\n    def class_name(cls) -> str:\n        return "MlflowSpanHandler"\n\n    def get_span_for_event(self, event: BaseEvent) -> LiveSpan:\n        llama_span = self.open_spans.get(event.span_id) or self._pending_spans.get(event.span_id)\n        return llama_span._mlflow_span if llama_span else None\n\n    def new_span(\n        self,\n        id_: str,\n        bound_args: inspect.BoundArguments,\n        instance: Any | None = None,\n        parent_span_id: str | None = None,\n        **kwargs: Any,\n    ) -> _LlamaSpan:\n        with self.lock:\n            parent = self.open_spans.get(parent_span_id) if parent_span_id else None\n\n        parent_span = parent._mlflow_span if parent else mlflow.get_current_active_span()\n\n        try:\n            input_args = bound_args.arguments\n            attributes = self._get_instance_attributes(instance)\n            span_type = self._get_span_type(instance) or SpanType.UNKNOWN\n            span = start_span_no_context(\n                name=id_.partition("-")[0],\n                parent_span=parent_span,\n                span_type=span_type,\n                inputs=input_args,\n                attributes=attributes,\n            )\n\n            token = set_span_in_context(span)\n            self._span_id_to_token[span.span_id] = token\n\n            # NB: The tool definition is passed to LLM via kwargs, but it is not set\n            # to the LLM/Chat start event. Therefore, we need to handle it here.\n            tools = input_args.get("kwargs", {}).get("tools")\n            if tools and span_type in [SpanType.LLM, SpanType.CHAT_MODEL]:\n                try:\n                    set_span_chat_tools(span, tools)\n                except Exception as e:\n                    _logger.debug(f"Failed to set tools for {span}: {e}")\n\n            return _LlamaSpan(id_=id_, parent_id=parent_span_id, mlflow_span=span)\n        except BaseException as e:\n            _logger.debug(f"Failed to create a new span: {e}", exc_info=True)\n\n    def prepare_to_exit_span(\n        self,\n        id_: str,\n        result: Any | None = None,\n        **kwargs: Any,\n    ) -> _LlamaSpan:\n        try:\n            with self.lock:\n                llama_span = self.open_spans.get(id_)\n            if not llama_span:\n                return\n\n            span = llama_span._mlflow_span\n            token = self._span_id_to_token.pop(span.span_id, None)\n\n            if _is_workflow_handler(result):\n                # In llama-index-workflows >= 2.0, Workflow.run() is synchronous and returns\n                # a WorkflowHandler instead of the actual result. Keep the span open so child\n                # step spans can properly link to it, and close it when a StopEvent is received.\n                self._pending_workflow_span_ids.add(id_)\n                if token:\n                    detach_span_from_context(token)\n                return None  # Keep the span in open_spans\n            elif self._stream_resolver.is_streaming_result(result):\n                # If the result is a generator, we keep the span in progress for streaming\n                # and end it when the generator is exhausted.\n                is_pended = self._stream_resolver.register_stream_span(span, result)\n                if is_pended:\n                    self._pending_spans[id_] = llama_span\n                    # We still need to detach the span from the context, otherwise it will\n                    # be considered as "active"\n                    detach_span_from_context(token)\n                else:\n                    # If the span is not pended successfully, end it immediately\n                    _end_span(span=span, outputs=result, token=token)\n            else:\n                _end_span(span=span, outputs=result, token=token)\n\n            # If a child step returns a StopEvent, close the parent workflow span\n            self._try_close_workflow_span(llama_span.parent_id, result)\n\n            return llama_span\n        except BaseException as e:\n            _logger.debug(f"Failed to end a span: {e}", exc_info=True)\n\n    def _try_close_workflow_span(self, parent_id: str | None, result: Any):\n        """Close a pending workflow span when a child step returns a StopEvent."""\n        if not parent_id or parent_id not in self._pending_workflow_span_ids:\n            return\n\n        try:\n            from llama_index.core.workflow import StopEvent\n\n            if not isinstance(result, StopEvent):\n                return\n        except ImportError:\n            return\n\n        self._pending_workflow_span_ids.discard(parent_id)\n        with self.lock:\n            workflow_llama_span = self.open_spans.pop(parent_id, None)\n        if workflow_llama_span:\n            _end_span(span=workflow_llama_span._mlflow_span, outputs=result.result)\n\n    def resolve_pending_stream_span(self, span: LiveSpan, event: Any):\n        """End the pending streaming span(s)"""\n        self._stream_resolver.resolve(span, event)\n        self._pending_spans.pop(event.span_id, None)\n\n    def prepare_to_drop_span(self, id_: str, err: Exception | None, **kwargs) -> _LlamaSpan:\n        """Logic for handling errors during the model execution."""\n        with self.lock:\n            llama_span = self.open_spans.get(id_)\n        span = llama_span._mlflow_span\n        token = self._span_id_to_token.pop(span.span_id, None)\n\n        if _get_llama_index_version() >= Version("0.10.59"):\n            # LlamaIndex determines if a workflow is terminated or not by propagating an special\n            # exception WorkflowDone. We should treat this exception as a successful termination.\n            from llama_index.core.workflow.errors import WorkflowDone\n\n            if err and isinstance(err, WorkflowDone):\n                return _end_span(span=span, status=SpanStatusCode.OK, token=token)\n\n        span.add_event(SpanEvent.from_exception(err))\n        _end_span(span=span, status="ERROR", token=token)\n        return llama_span\n\n    def _get_span_type(self, instance: Any) -> SpanType:\n        """\n        Map LlamaIndex instance type to MLflow span type. Some span type cannot be determined\n        by instance type alone, rather need event info e.g. ChatModel, ReRanker\n        """\n        base_agent_types = ()\n        if _get_llama_index_version() < Version("0.13.0"):\n            from llama_index.core.base.agent.types import BaseAgent, BaseAgentWorker\n\n            base_agent_types = (BaseAgent, BaseAgentWorker)\n        else:\n            from llama_index.core.agent.workflow import BaseWorkflowAgent\n\n            base_agent_types = (BaseWorkflowAgent,)\n\n        if isinstance(instance, (BaseLLM, MultiModalLLM)):\n            return SpanType.LLM\n        elif isinstance(instance, BaseRetriever):\n            return SpanType.RETRIEVER\n        elif isinstance(instance, base_agent_types):\n            return SpanType.AGENT\n        elif isinstance(instance, BaseEmbedding):\n            return SpanType.EMBEDDING\n        elif isinstance(instance, BaseTool):\n            return SpanType.TOOL\n        else:\n            return SpanType.CHAIN\n\n    @singledispatchmethod\n    def _get_instance_attributes(self, instance: Any) -> dict[str, Any]:\n        """\n        Extract span attributes from LlamaIndex objects.\n\n        NB: There are some overlap between attributes extracted from instance metadata and the\n        events. For example, model name for an LLM is available in both. However, events might\n        not always be triggered (e.g. 3P llm integration doesn\'t implement the event logic),\n        so the instance metadata serves as a fallback source of information.\n        """\n\n    # TODO: Union type hint doesn\'t work with singledispatchmethod, so we have to define\n    #  two separate methods for BaseLLM and MultiModalLLM. Once we upgrade to Python 3.10,\n    #  we can use `BaseLLM | MultiModelLLM` type hint and it works with singledispatchmethod.\n    @_get_instance_attributes.register\n    def _(self, instance: BaseLLM):\n        return self._get_llm_attributes(instance)\n\n    @_get_instance_attributes.register\n    def _(self, instance: MultiModalLLM):\n        return self._get_llm_attributes(instance)\n\n    def _get_llm_attributes(self, instance) -> dict[str, Any]:\n        attr = {SpanAttributeKey.MESSAGE_FORMAT: "llamaindex"}\n        if metadata := instance.metadata:\n            attr["model_name"] = metadata.model_name\n            attr[SpanAttributeKey.MODEL] = metadata.model_name\n            if params_str := metadata.model_dump_json(exclude_unset=True):\n                attr["invocation_params"] = json.loads(params_str)\n        # LlamaIndex LLM class names map directly to providers\n        # e.g., OpenAI, Anthropic, Gemini, Bedrock, etc.\n        attr[SpanAttributeKey.MODEL_PROVIDER] = instance.__class__.__name__.lower()\n        return attr\n\n    @_get_instance_attributes.register\n    def _(self, instance: BaseEmbedding):\n        return {\n            "model_name": instance.model_name,\n            SpanAttributeKey.MODEL: instance.model_name,\n            SpanAttributeKey.MODEL_PROVIDER: instance.__class__.__name__.lower(),\n            "embed_batch_size": instance.embed_batch_size,\n        }\n\n    @_get_instance_attributes.register\n    def _(self, instance: BaseTool):\n        metadata = instance.metadata\n        attributes = {"description": metadata.description}\n        try:\n            attributes["name"] = metadata.name\n        except ValueError:\n            # ToolMetadata.get_name() raises ValueError if name is None\n            pass\n        try:\n            attributes["parameters"] = json.loads(metadata.fn_schema_str)\n        except ValueError:\n            # ToolMetadata.get_fn_schema_str() raises ValueError if fn_schema is None\n            pass\n        return attributes\n\n\nclass MlflowEventHandler(BaseEventHandler, extra="allow"):\n    """\n    Event handler processes various events that are triggered during execution.\n\n    Events are used as supplemental source for recording additional metadata to the span,\n    such as model name, parameters to the span, because they are not available in the inputs\n    and outputs in SpanHandler.\n    """\n\n    _span_handler: MlflowSpanHandler\n\n    @classmethod\n    def class_name(cls) -> str:\n        return "MlflowEventHandler"\n\n    def __init__(self, _span_handler):\n        super().__init__()\n        self._span_handler = _span_handler\n\n    def handle(self, event: BaseEvent) -> Any:\n        try:\n            if span := self._span_handler.get_span_for_event(event):\n                self._handle_event(event, span)\n        except Exception as e:\n            _logger.debug(f"Failed to handle event: {e}", exc_info=True)\n\n    @singledispatchmethod\n    def _handle_event(self, event: BaseEvent, span: LiveSpan):\n        # Pass through the events we are not interested in\n        pass\n\n    @_handle_event.register\n    def _(self, event: AgentToolCallEvent, span: LiveSpan):\n        span.set_attribute("name", event.tool.name)\n        span.set_attribute("description", event.tool.description)\n        span.set_attribute("parameters", event.tool.get_parameters_dict())\n\n    @_handle_event.register\n    def _(self, event: EmbeddingStartEvent, span: LiveSpan):\n        span.set_attribute("model_dict", event.model_dict)\n        self._extract_and_set_model_name(span, event.model_dict)\n\n    @_handle_event.register\n    def _(self, event: LLMPredictStartEvent, span: LiveSpan):\n        """\n        An event triggered when LLM\'s predict() is called.\n\n        In LlamaIndex, predict() is a gateway method that dispatch the request to\n        either chat() or completion() method depending on the model type, as well\n        as crafting prompt from the template.\n        """\n        template = event.template\n        template_args = {\n            **template.kwargs,\n            **(event.template_args or {}),\n        }\n        span.set_attributes({\n            "prmopt_template": template.get_template(),\n            "template_arguments": {var: template_args.get(var) for var in template_args},\n        })\n\n    @_handle_event.register\n    def _(self, event: LLMCompletionStartEvent, span: LiveSpan):\n        span.set_attribute("prompt", event.prompt)\n        span.set_attribute("model_dict", event.model_dict)\n        self._extract_and_set_model_name(span, event.model_dict)\n\n    @_handle_event.register\n    def _(self, event: LLMCompletionEndEvent, span: LiveSpan):\n        span.set_attribute("usage", self._extract_token_usage(event.response))\n        token_counts = self._parse_usage(span)\n        span.set_attribute(SpanAttributeKey.CHAT_USAGE, token_counts)\n        self._span_handler.resolve_pending_stream_span(span, event)\n\n    @_handle_event.register\n    def _(self, event: LLMChatStartEvent, span: LiveSpan):\n        span.set_attribute(SpanAttributeKey.SPAN_TYPE, SpanType.CHAT_MODEL)\n        span.set_attribute("model_dict", event.model_dict)\n        self._extract_and_set_model_name(span, event.model_dict)\n\n    @_handle_event.register\n    def _(self, event: LLMChatEndEvent, span: LiveSpan):\n        span.set_attribute("usage", self._extract_token_usage(event.response))\n        token_counts = self._parse_usage(span)\n        span.set_attribute(SpanAttributeKey.CHAT_USAGE, token_counts)\n        self._span_handler.resolve_pending_stream_span(span, event)\n\n    @_handle_event.register\n    def _(self, event: ReRankStartEvent, span: LiveSpan):\n        span.set_attribute(SpanAttributeKey.SPAN_TYPE, SpanType.RERANKER)\n        span.set_attributes({\n            "model_name": event.model_name,\n            "top_n": event.top_n,\n        })\n\n    @_handle_event.register\n    def _(self, event: ExceptionEvent, span: LiveSpan):\n        """\n        Handle an exception event for stream spans.\n\n        For non-stream spans, exception is processed by the prepare_to_drop_span() handler of\n        the span handler. However, for stream spans, the exception may raised during the\n        streaming after it exit. Therefore, we need to resolve the span here.\n        """\n        self._span_handler.resolve_pending_stream_span(span, event)\n\n    def _extract_and_set_model_name(self, span: LiveSpan, model_dict: dict[str, Any] | None):\n        if model_dict and (model := model_dict.get("model")):\n            span.set_attribute(SpanAttributeKey.MODEL, model)\n            if isinstance(model, str):\n                match model.split("/", 1):\n                    case [provider, _]:\n                        span.set_attribute(SpanAttributeKey.MODEL_PROVIDER, provider)\n\n    def _extract_token_usage(self, response: ChatResponse | CompletionResponse) -> dict[str, int]:\n        if raw := response.raw:\n            # The raw response can be a Pydantic model or a dictionary\n            if isinstance(raw, pydantic.BaseModel):\n                raw = raw.model_dump()\n\n            if usage := raw.get("usage"):\n                return usage\n\n        # If the usage is not found in the raw response, look for token counts\n        # in additional_kwargs of the completion payload\n        usage = {}\n        if additional_kwargs := getattr(response, "additional_kwargs", None):\n            for k in ["prompt_tokens", "completion_tokens", "total_tokens"]:\n                if (v := additional_kwargs.get(k)) is not None:\n                    usage[k] = v\n        return usage\n\n    def _parse_usage(self, span: LiveSpan):\n        try:\n            usage = span.get_attribute("usage")\n            return {\n                TokenUsageKey.INPUT_TOKENS: usage["prompt_tokens"],\n                TokenUsageKey.OUTPUT_TOKENS: usage["completion_tokens"],\n                TokenUsageKey.TOTAL_TOKENS: usage.get(\n                    "total_tokens", usage["prompt_tokens"] + usage["completion_tokens"]\n                ),\n            }\n        except Exception as e:\n            _logger.debug(f"Failed to set TokenUsage to the span: {e}", exc_info=True)\n\n\n_StreamEndEvent = LLMChatEndEvent | LLMCompletionEndEvent | ExceptionEvent\n\n\ndef _get_task_step_output_type():\n    if _get_llama_index_version() < Version("0.13.0"):\n        from llama_index.core.base.agent.types import TaskStepOutput\n\n        return TaskStepOutput\n    return ()\n\n\nclass StreamResolver:\n    """\n    A class is responsible for closing the pending streaming spans that are waiting\n    for the stream to be exhausted. Once the associated stream is exhausted, this\n    class will resolve the span, as well as recursively resolve the parent spans\n    that returns the same (or derived) stream.\n    """\n\n    def __init__(self):\n        self._span_id_to_span_and_gen: dict[str, tuple[LiveSpan, Generator]] = {}\n\n    def is_streaming_result(self, result: Any) -> bool:\n        return (\n            inspect.isgenerator(result)  # noqa: SIM101\n            or isinstance(result, (StreamingResponse, AsyncStreamingResponse))\n            or isinstance(result, StreamingAgentChatResponse)\n            or (\n                isinstance(result, _get_task_step_output_type())\n                and self.is_streaming_result(result.output)\n            )\n        )\n\n    def register_stream_span(self, span: LiveSpan, result: Any) -> bool:\n        """\n        Register the pending streaming span with the associated generator.\n\n        Args:\n            span: The span that has a streaming output.\n            result: The streaming result that is being processed.\n\n        Returns:\n            True if the span is registered successfully, False otherwise.\n        """\n        if inspect.isgenerator(result) or inspect.isasyncgen(result):\n            stream = result\n        elif isinstance(result, (StreamingResponse, AsyncStreamingResponse)):\n            stream = result.response_gen\n        elif isinstance(result, StreamingAgentChatResponse):\n            stream = result.chat_stream\n        elif isinstance(result, _get_task_step_output_type()):\n            stream = result.output.chat_stream\n        else:\n            raise ValueError(f"Unsupported streaming response type: {type(result)}")\n\n        # Check if generator/async generator is already closed\n        # Async generators use ag_frame, sync generators use gi_frame\n        if inspect.isasyncgen(stream):\n            # For async generators, ag_frame is None when closed\n            if stream.ag_frame is None:\n                return False\n        elif inspect.isgenerator(stream):\n            # For sync generators, use getgeneratorstate\n            if inspect.getgeneratorstate(stream) == inspect.GEN_CLOSED:\n                return False\n\n        self._span_id_to_span_and_gen[span.span_id] = (span, stream)\n        return True\n\n    def resolve(self, span: LiveSpan, event: _StreamEndEvent):\n        """\n        Finish the streaming span and recursively resolve the parent spans that\n        returns the same (or derived) stream.\n        """\n        _, stream = self._span_id_to_span_and_gen.pop(span.span_id, (None, None))\n        if not stream:\n            return\n\n        if isinstance(event, (LLMChatEndEvent, LLMCompletionEndEvent)):\n            outputs = event.response\n            status = SpanStatusCode.OK\n        elif isinstance(event, ExceptionEvent):\n            outputs = None\n            status = SpanStatusCode.ERROR\n            span.add_event(SpanEvent.from_exception(event.exception))\n        else:\n            raise ValueError(f"Unsupported event type to resolve streaming: {type(event)}")\n\n        _end_span(span=span, status=status, outputs=outputs)\n\n        # Extract the complete text from the event.\n        if isinstance(outputs, ChatResponse):\n            output_text = outputs.message.content\n        elif isinstance(outputs, CompletionResponse):\n            output_text = outputs.response.text\n        else:\n            output_text = None\n\n        # Recursively resolve the parent spans that are also waiting for the same token\n        # stream to be exhausted.\n        while span.parent_id in self._span_id_to_span_and_gen:\n            if span_and_stream := self._span_id_to_span_and_gen.pop(span.parent_id, None):\n                span, stream = span_and_stream\n                # We reuse the same output text for parent spans. This may not be 100% correct\n                # as token stream can be modified by callers. However, it is technically\n                # challenging to track the modified stream across multiple spans.\n                _end_span(span=span, status=status, outputs=output_text)\n',
            'tests/llama_index/test_llama_index_autolog.py': 'from unittest import mock\n\nimport importlib_metadata\nimport pytest\nfrom llama_index.core.chat_engine.types import ChatMode\nfrom llama_index.core.instrumentation import get_dispatcher\nfrom llama_index.core.instrumentation.event_handlers.base import BaseEventHandler\nfrom llama_index.core.instrumentation.span_handlers.base import BaseSpanHandler\nfrom llama_index.llms.openai import OpenAI\nfrom packaging.version import Version\n\nimport mlflow\nfrom mlflow.tracing.constant import TraceMetadataKey\n\nfrom tests.tracing.helper import get_traces, skip_when_testing_trace_sdk\n\nllama_core_version = Version(importlib_metadata.version("llama-index-core"))\n\n\ndef test_autolog_enable_tracing(multi_index):\n    mlflow.llama_index.autolog()\n\n    query_engine = multi_index.as_query_engine()\n\n    query_engine.query("Hello")\n    query_engine.query("Hola")\n\n    traces = get_traces()\n    assert len(traces) == 2\n\n    # Enabling autolog multiple times should not create duplicate spans\n    mlflow.llama_index.autolog()\n    mlflow.llama_index.autolog()\n\n    chat_engine = multi_index.as_chat_engine()\n    chat_engine.chat("Hello again!")\n\n    assert len(get_traces()) == 3\n\n    mlflow.llama_index.autolog(disable=True)\n    query_engine.query("Hello again!")\n\n    traces = get_traces()\n    assert len(get_traces()) == 3\n\n\ndef test_autolog_preserve_user_provided_handlers():\n    user_span_handler = mock.MagicMock(spec=BaseSpanHandler)\n    user_event_handler = mock.MagicMock(spec=BaseEventHandler)\n\n    dsp = get_dispatcher()\n    dsp.add_span_handler(user_span_handler)\n    dsp.add_event_handler(user_event_handler)\n\n    mlflow.llama_index.autolog()\n\n    llm = OpenAI()\n    llm.complete("Hello")\n\n    assert user_span_handler in dsp.span_handlers\n    assert user_event_handler in dsp.event_handlers\n    user_span_handler.span_enter.assert_called_once()\n    user_span_handler.span_exit.assert_called_once()\n    assert user_event_handler.handle.call_count == 2  # LLM start + end\n\n    traces = get_traces()\n    assert len(traces) == 1\n\n    user_span_handler.reset_mock()\n    user_event_handler.reset_mock()\n\n    mlflow.llama_index.autolog(disable=True)\n\n    assert user_span_handler in dsp.span_handlers\n    assert user_event_handler in dsp.event_handlers\n\n    llm.complete("Hello, again!")\n\n    user_span_handler.span_enter.assert_called_once()\n    user_span_handler.span_exit.assert_called_once()\n    assert user_event_handler.handle.call_count == 2\n\n    traces = get_traces()\n    assert len(traces) == 1\n\n\n@skip_when_testing_trace_sdk\ndef test_autolog_should_not_generate_traces_during_logging_loading(single_index):\n    mlflow.llama_index.autolog()\n\n    with mlflow.start_run():\n        model_info = mlflow.llama_index.log_model(\n            single_index,\n            name="model",\n            pip_requirements=["mlflow"],\n            engine_type="query",\n        )\n    loaded = mlflow.pyfunc.load_model(model_info.model_uri)\n\n    assert len(get_traces()) == 0\n\n    loaded.predict("Hello")\n    assert len(get_traces()) == 1\n\n\n@skip_when_testing_trace_sdk\n@pytest.mark.parametrize(\n    ("code_path", "engine_type", "engine_method", "input_arg"),\n    [\n        (\n            "tests/llama_index/sample_code/query_engine_with_reranker.py",\n            "query",\n            "query",\n            "str_or_query_bundle",\n        ),\n        ("tests/llama_index/sample_code/basic_chat_engine.py", "chat", "chat", "message"),\n        (\n            "tests/llama_index/sample_code/basic_retriever.py",\n            "retriever",\n            "retrieve",\n            "str_or_query_bundle",\n        ),\n    ],\n)\ndef test_autolog_link_traces_to_loaded_model_engine(\n    code_path, engine_type, engine_method, input_arg\n):\n    model_infos = []\n    for i in range(3):\n        with mlflow.start_run():\n            model_infos.append(\n                mlflow.llama_index.log_model(\n                    code_path,\n                    name=f"model_{i}",\n                    pip_requirements=["mlflow"],\n                    engine_type=engine_type,\n                )\n            )\n\n    mlflow.llama_index.autolog()\n    for model_info in model_infos:\n        model = mlflow.llama_index.load_model(model_info.model_uri)\n        getattr(model, engine_method)(f"Hello {model_info.model_id}")\n\n    traces = get_traces()\n    assert len(traces) == 3\n    for trace in traces:\n        span = trace.data.spans[0]\n        model_id = trace.info.request_metadata[TraceMetadataKey.MODEL_ID]\n        assert model_id is not None\n        assert span.inputs[input_arg] == f"Hello {model_id}"\n\n\n@skip_when_testing_trace_sdk\n@pytest.mark.parametrize("is_stream", [False, True])\ndef test_autolog_link_traces_to_loaded_model_index_query(single_index, is_stream):\n    model_infos = []\n    for i in range(3):\n        with mlflow.start_run():\n            model_infos.append(\n                mlflow.llama_index.log_model(\n                    single_index,\n                    name=f"model_{i}",\n                    pip_requirements=["mlflow"],\n                    engine_type="query",\n                )\n            )\n\n    mlflow.llama_index.autolog()\n    for model_info in model_infos:\n        model = mlflow.llama_index.load_model(model_info.model_uri)\n        engine = model.as_query_engine(streaming=is_stream)\n        response = engine.query(f"Hello {model_info.model_id}")\n        if is_stream:\n            response = "".join(response.response_gen)\n\n    traces = get_traces()\n    assert len(traces) == 3\n    for trace in traces:\n        span = trace.data.spans[0]\n        model_id = trace.info.request_metadata[TraceMetadataKey.MODEL_ID]\n        assert span.inputs["str_or_query_bundle"] == f"Hello {model_id}"\n\n\n@skip_when_testing_trace_sdk\n@pytest.mark.asyncio\nasync def test_autolog_link_traces_to_loaded_model_index_query_async(single_index):\n    model_infos = []\n    for i in range(3):\n        with mlflow.start_run():\n            model_infos.append(\n                mlflow.llama_index.log_model(\n                    single_index,\n                    name=f"model_{i}",\n                    pip_requirements=["mlflow"],\n                    engine_type="query",\n                )\n            )\n\n    mlflow.llama_index.autolog()\n    for model_info in model_infos:\n        model = mlflow.llama_index.load_model(model_info.model_uri)\n        engine = model.as_query_engine()\n        await engine.aquery(f"Hello {model_info.model_id}")\n\n    traces = get_traces()\n    assert len(traces) == 3\n    for trace in traces:\n        span = trace.data.spans[0]\n        model_id = trace.info.request_metadata[TraceMetadataKey.MODEL_ID]\n        assert span.inputs["str_or_query_bundle"] == f"Hello {model_id}"\n\n\n@skip_when_testing_trace_sdk\n@pytest.mark.parametrize(\n    "chat_mode",\n    [\n        ChatMode.BEST,\n        ChatMode.CONTEXT,\n        ChatMode.CONDENSE_QUESTION,\n        ChatMode.CONDENSE_PLUS_CONTEXT,\n        ChatMode.SIMPLE,\n        ChatMode.REACT,\n        ChatMode.OPENAI,\n    ],\n)\ndef test_autolog_link_traces_to_loaded_model_index_chat(single_index, chat_mode):\n    if llama_core_version >= Version("0.13.0") and chat_mode in [ChatMode.OPENAI, ChatMode.REACT]:\n        pytest.skip("OpenAI and React chat modes are removed in 0.13.0")\n\n    model_infos = []\n    for i in range(3):\n        with mlflow.start_run():\n            model_infos.append(\n                mlflow.llama_index.log_model(\n                    single_index, name=f"model_{i}", pip_requirements=["mlflow"], engine_type="chat"\n                )\n            )\n\n    mlflow.llama_index.autolog()\n    for model_info in model_infos:\n        model = mlflow.llama_index.load_model(model_info.model_uri)\n        engine = model.as_chat_engine(chat_mode=chat_mode)\n        engine.chat(f"Hello {model_info.model_id}")\n\n    traces = get_traces()\n    assert len(traces) == 3\n    for trace in traces:\n        span = trace.data.spans[0]\n        model_id = trace.info.request_metadata[TraceMetadataKey.MODEL_ID]\n        assert span.inputs["message"] == f"Hello {model_id}"\n\n\n@skip_when_testing_trace_sdk\ndef test_autolog_link_traces_to_loaded_model_index_retriever(single_index):\n    model_infos = []\n    for i in range(3):\n        with mlflow.start_run():\n            model_infos.append(\n                mlflow.llama_index.log_model(\n                    single_index,\n                    name=f"model_{i}",\n                    pip_requirements=["mlflow"],\n                    engine_type="retriever",\n                )\n            )\n\n    mlflow.llama_index.autolog()\n    for model_info in model_infos:\n        model = mlflow.llama_index.load_model(model_info.model_uri)\n        engine = model.as_retriever()\n        engine.retrieve(f"Hello {model_info.model_id}")\n\n    traces = get_traces()\n    assert len(traces) == 3\n    for trace in traces:\n        span = trace.data.spans[0]\n        model_id = trace.info.request_metadata[TraceMetadataKey.MODEL_ID]\n        assert span.inputs["str_or_query_bundle"] == f"Hello {model_id}"\n\n\n@skip_when_testing_trace_sdk\n@pytest.mark.skipif(\n    llama_core_version < Version("0.11.0"),\n    reason="Workflow was introduced in 0.11.0",\n)\n@pytest.mark.asyncio\nasync def test_autolog_link_traces_to_loaded_model_workflow():\n    mlflow.llama_index.autolog()\n    with mlflow.start_run():\n        model_info = mlflow.llama_index.log_model(\n            "tests/llama_index/sample_code/simple_workflow.py",\n            name="model",\n            pip_requirements=["mlflow"],\n        )\n    loaded_workflow = mlflow.llama_index.load_model(model_info.model_uri)\n    await loaded_workflow.run(topic=f"Hello {model_info.model_id}")\n\n    traces = get_traces()\n    assert len(traces) == 1\n    span = traces[0].data.spans[0]\n    model_id = traces[0].info.request_metadata[TraceMetadataKey.MODEL_ID]\n    assert model_id is not None\n    assert span.inputs["kwargs"]["topic"] == f"Hello {model_id}"\n\n\n@skip_when_testing_trace_sdk\n@pytest.mark.skipif(\n    llama_core_version < Version("0.11.0"),\n    reason="Workflow was introduced in 0.11.0",\n)\ndef test_autolog_link_traces_to_loaded_model_workflow_pyfunc():\n    mlflow.llama_index.autolog()\n    with mlflow.start_run():\n        model_info = mlflow.llama_index.log_model(\n            "tests/llama_index/sample_code/simple_workflow.py",\n            name="model",\n            pip_requirements=["mlflow"],\n        )\n    loaded_workflow = mlflow.pyfunc.load_model(model_info.model_uri)\n    loaded_workflow.predict({"topic": f"Hello {model_info.model_id}"})\n\n    traces = get_traces()\n    assert len(traces) == 1\n    span = traces[0].data.spans[0]\n    model_id = traces[0].info.request_metadata[TraceMetadataKey.MODEL_ID]\n    assert model_id is not None\n    assert span.inputs["kwargs"]["topic"] == f"Hello {model_id}"\n\n\n@skip_when_testing_trace_sdk\n@pytest.mark.skipif(\n    llama_core_version < Version("0.11.0"),\n    reason="Workflow was introduced in 0.11.0",\n)\ndef test_autolog_link_traces_to_active_model():\n    model = mlflow.create_external_model(name="test_model")\n    mlflow.set_active_model(model_id=model.model_id)\n    mlflow.llama_index.autolog()\n    with mlflow.start_run():\n        model_info = mlflow.llama_index.log_model(\n            "tests/llama_index/sample_code/simple_workflow.py",\n            name="model",\n            pip_requirements=["mlflow"],\n        )\n    loaded_workflow = mlflow.pyfunc.load_model(model_info.model_uri)\n    loaded_workflow.predict({"topic": f"Hello {model_info.model_id}"})\n\n    traces = get_traces()\n    assert len(traces) == 1\n    model_id = traces[0].info.request_metadata[TraceMetadataKey.MODEL_ID]\n    assert model_id == model.model_id\n    assert model_id != model_info.model_id\n\n\n@skip_when_testing_trace_sdk\n@pytest.mark.skipif(\n    llama_core_version < Version("0.11.0"),\n    reason="Workflow was introduced in 0.11.0",\n)\ndef test_model_loading_set_active_model_id_without_fetching_logged_model():\n    mlflow.llama_index.autolog()\n    model_info = mlflow.llama_index.log_model(\n        "tests/llama_index/sample_code/simple_workflow.py",\n        name="model",\n        pip_requirements=["mlflow"],\n    )\n    with mock.patch("mlflow.get_logged_model", side_effect=Exception("get_logged_model failed")):\n        loaded_workflow = mlflow.pyfunc.load_model(model_info.model_uri)\n    loaded_workflow.predict({"topic": f"Hello {model_info.model_id}"})\n\n    traces = get_traces()\n    assert len(traces) == 1\n    span = traces[0].data.spans[0]\n    model_id = traces[0].info.request_metadata[TraceMetadataKey.MODEL_ID]\n    assert model_id is not None\n    assert span.inputs["kwargs"]["topic"] == f"Hello {model_id}"\n',
            'tests/llama_index/test_llama_index_tracer.py': 'import asyncio\nimport base64\nimport inspect\nimport random\nfrom dataclasses import asdict\nfrom pathlib import Path\nfrom typing import Any\nfrom unittest.mock import ANY\n\nimport importlib_metadata\nimport llama_index.core\nimport openai\nimport pytest\nfrom llama_index.core import Settings\nfrom llama_index.core.base.response.schema import StreamingResponse\nfrom llama_index.core.llms import ChatMessage, ChatResponse\nfrom llama_index.core.llms.callbacks import llm_chat_callback\nfrom llama_index.core.retrievers import VectorIndexRetriever\nfrom llama_index.core.tools import FunctionTool\nfrom llama_index.core.workflow import Context\nfrom llama_index.llms.openai import OpenAI\nfrom openai.types.chat import ChatCompletionMessageToolCall\nfrom packaging.version import Version\n\nimport mlflow\nfrom mlflow.entities.span import SpanType\nfrom mlflow.entities.span_status import SpanStatusCode\nfrom mlflow.entities.trace_status import TraceStatus\nfrom mlflow.llama_index.tracer import (\n    StreamResolver,\n    remove_llama_index_tracer,\n    set_llama_index_tracer,\n)\nfrom mlflow.tracing.constant import SpanAttributeKey, TokenUsageKey\nfrom mlflow.tracing.provider import _get_tracer\nfrom mlflow.tracking._tracking_service.utils import _use_tracking_uri\nfrom mlflow.version import IS_TRACING_SDK_ONLY\n\nfrom tests.tracing.helper import get_traces, skip_when_testing_trace_sdk\n\nllama_core_version = Version(importlib_metadata.version("llama-index-core"))\nllama_oai_version = Version(importlib_metadata.version("llama-index-llms-openai"))\n\n# Detect llama-index-workflows version to handle API changes\ntry:\n    llama_workflows_version = Version(importlib_metadata.version("llama-index-workflows"))\nexcept importlib_metadata.PackageNotFoundError:\n    llama_workflows_version = None\n\n\n@pytest.fixture(autouse=True)\ndef set_handlers():\n    set_llama_index_tracer()\n    yield\n    # Clean up\n    remove_llama_index_tracer()\n\n\n@pytest.mark.parametrize("is_async", [True, False])\ndef test_trace_llm_complete(is_async, mock_litellm_cost):\n    # By default llama-index uses "gpt-3.5-turbo" model that only has chat interface,\n    # and llama-index redirects completion call to chat endpoint. We use non-chat\n    # model here to test trace for completion.\n    model_name = "gpt-3.5-turbo-instruct"\n    llm = OpenAI(model=model_name)\n\n    response = asyncio.run(llm.acomplete("Hello")) if is_async else llm.complete("Hello")\n    assert response.text == "Hello"\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    spans = traces[0].data.spans\n    assert len(spans) == 1\n    assert spans[0].name == "OpenAI.{}complete".format("a" if is_async else "")\n    assert spans[0].span_type == SpanType.LLM\n    assert spans[0].inputs == {"args": ["Hello"]}\n    assert spans[0].outputs["text"] == "Hello"\n\n    attr = spans[0].attributes\n    assert (\n        attr["usage"].items()\n        >= {\n            "prompt_tokens": 5,\n            "completion_tokens": 7,\n            "total_tokens": 12,\n            "completion_tokens_details": None,\n            "prompt_tokens_details": None,\n        }.items()\n    )\n    assert attr[SpanAttributeKey.CHAT_USAGE] == {\n        TokenUsageKey.INPUT_TOKENS: 5,\n        TokenUsageKey.OUTPUT_TOKENS: 7,\n        TokenUsageKey.TOTAL_TOKENS: 12,\n    }\n\n    assert attr["prompt"] == "Hello"\n    assert attr["invocation_params"]["model_name"] == model_name\n    assert attr["model_dict"]["model"] == model_name\n    assert spans[0].model_name == model_name\n\n    assert traces[0].info.token_usage == {\n        TokenUsageKey.INPUT_TOKENS: 5,\n        TokenUsageKey.OUTPUT_TOKENS: 7,\n        TokenUsageKey.TOTAL_TOKENS: 12,\n    }\n\n    if not IS_TRACING_SDK_ONLY:\n        # Verify cost is calculated\n        assert spans[0].llm_cost == {\n            "input_cost": 5.0,\n            "output_cost": 14.0,\n            "total_cost": 19.0,\n        }\n\n\ndef test_trace_llm_complete_stream():\n    model_name = "gpt-3.5-turbo"\n    llm = OpenAI(model=model_name)\n\n    response_gen = llm.stream_complete("Hello", stream_options={"include_usage": True})\n    # No trace should be created until the generator is consumed\n    assert len(get_traces()) == 0\n    assert inspect.isgenerator(response_gen)\n\n    response = [r.text for r in response_gen]\n    assert response == ["Hello", "Hello world"]\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    spans = traces[0].data.spans\n    assert len(spans) == 1\n    assert spans[0].name == "OpenAI.stream_complete"\n    assert spans[0].span_type == SpanType.LLM\n    assert spans[0].inputs == {\n        "args": ["Hello"],\n        "kwargs": {"stream_options": {"include_usage": True}},\n    }\n    assert spans[0].outputs["text"] == "Hello world"\n\n    attr = spans[0].attributes\n    assert (\n        attr["usage"].items()\n        >= {\n            "prompt_tokens": 9,\n            "completion_tokens": 12,\n            "total_tokens": 21,\n            "completion_tokens_details": None,\n            "prompt_tokens_details": None,\n        }.items()\n    )\n    assert attr[SpanAttributeKey.CHAT_USAGE] == {\n        TokenUsageKey.INPUT_TOKENS: 9,\n        TokenUsageKey.OUTPUT_TOKENS: 12,\n        TokenUsageKey.TOTAL_TOKENS: 21,\n    }\n    assert attr["prompt"] == "Hello"\n    assert attr["invocation_params"]["model_name"] == model_name\n    assert attr["model_dict"]["model"] == model_name\n    assert spans[0].model_name == model_name\n    assert traces[0].info.token_usage == {\n        TokenUsageKey.INPUT_TOKENS: 9,\n        TokenUsageKey.OUTPUT_TOKENS: 12,\n        TokenUsageKey.TOTAL_TOKENS: 21,\n    }\n\n\ndef _get_llm_input_content_json(content):\n    if Version(llama_index.core.__version__) >= Version("0.12.5"):\n        # in llama-index >= 0.12.5, the input content json format is changed to\n        # {"blocks": {"block_type": "text", "text": <content>} }\n        return {\n            "blocks": [\n                {\n                    "block_type": "text",\n                    "text": content,\n                }\n            ]\n        }\n    return {"content": content}\n\n\n@pytest.mark.parametrize("is_async", [True, False])\ndef test_trace_llm_chat(is_async, mock_litellm_cost):\n    llm = OpenAI()\n    message = ChatMessage(role="system", content="Hello")\n\n    response = asyncio.run(llm.achat([message])) if is_async else llm.chat([message])\n    assert isinstance(response.message, ChatMessage)\n    assert response.message.content == \'[{"role": "system", "content": "Hello"}]\'\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    spans = traces[0].data.spans\n    assert len(spans) == 1\n    assert spans[0].name == "OpenAI.achat" if is_async else "OpenAI.chat"\n    assert spans[0].span_type == SpanType.CHAT_MODEL\n    assert spans[0].model_name == llm.metadata.model_name\n\n    content_json = _get_llm_input_content_json("Hello")\n    assert spans[0].inputs == {\n        "messages": [{"role": "system", **content_json, "additional_kwargs": {}}]\n    }\n    # `additional_kwargs` was broken until 0.1.30 release of llama-index-llms-openai\n    expected_kwargs = (\n        {"completion_tokens": 12, "prompt_tokens": 9, "total_tokens": 21}\n        if llama_oai_version >= Version("0.1.30")\n        else {}\n    )\n    output_content_json = _get_llm_input_content_json(\'[{"role": "system", "content": "Hello"}]\')\n    assert spans[0].outputs == {\n        "message": {\n            "role": "assistant",\n            **output_content_json,\n            "additional_kwargs": {},\n        },\n        "raw": ANY,\n        "delta": None,\n        "logprobs": None,\n        "additional_kwargs": expected_kwargs,\n    }\n\n    attr = spans[0].attributes\n    assert (\n        attr["usage"].items()\n        >= {\n            "prompt_tokens": 9,\n            "completion_tokens": 12,\n            "total_tokens": 21,\n            "completion_tokens_details": None,\n            "prompt_tokens_details": None,\n        }.items()\n    )\n    assert attr[SpanAttributeKey.CHAT_USAGE] == {\n        TokenUsageKey.INPUT_TOKENS: 9,\n        TokenUsageKey.OUTPUT_TOKENS: 12,\n        TokenUsageKey.TOTAL_TOKENS: 21,\n    }\n    assert attr["invocation_params"]["model_name"] == llm.metadata.model_name\n    assert attr["model_dict"]["model"] == llm.metadata.model_name\n    assert spans[0].model_name == llm.metadata.model_name\n    if not IS_TRACING_SDK_ONLY:\n        assert spans[0].llm_cost == {\n            "input_cost": 9.0,\n            "output_cost": 24.0,\n            "total_cost": 33.0,\n        }\n    assert traces[0].info.token_usage == {\n        TokenUsageKey.INPUT_TOKENS: 9,\n        TokenUsageKey.OUTPUT_TOKENS: 12,\n        TokenUsageKey.TOTAL_TOKENS: 21,\n    }\n\n\ndef _get_image_content(image_path):\n    with open(image_path, "rb") as f:\n        content = f.read()\n        return base64.b64encode(content).decode("utf-8")\n\n\ndef _multi_modal_test_cases():\n    if llama_core_version < Version("0.12.0"):\n        return []\n\n    from llama_index.core.base.llms.types import ImageBlock\n\n    image_dir = Path(__file__).parent.parent / "resources" / "images"\n\n    image_base64 = _get_image_content(str(image_dir / "test.png"))\n    test_cases = [\n        (\n            ImageBlock(url="https://example/image.jpg"),\n            {"url": "https://example/image.jpg"}\n            if llama_core_version < Version("0.12.30")\n            else {"url": "https://example/image.jpg", "detail": "auto"},\n        ),\n        # LlamaIndex support passing local image path\n        (\n            ImageBlock(path=str(image_dir / "test.png"), image_mimetype="image/png"),\n            {\n                "url": f"data:image/png;base64,{image_base64}",\n                "detail": "low" if llama_core_version < Version("0.12.25") else "auto",\n            },\n        ),\n    ]\n\n    # LlamaIndex < 0.12.3 doesn\'t support image content in byte format\n    if llama_core_version >= Version("0.12.3"):\n        image_bytes = _get_image_content(str(image_dir / "test.png"))\n        test_cases.append(\n            (\n                ImageBlock(image=image_bytes, detail="low"),\n                {\n                    "url": f"data:image/png;base64,{image_bytes}",\n                    "detail": "low",\n                },\n            ),\n        )\n\n    return test_cases\n\n\n@pytest.mark.skipif(llama_core_version < Version("0.12.0"), reason="Multi-modal not supported")\n@pytest.mark.parametrize(("image_block", "expected_image_url"), _multi_modal_test_cases())\ndef test_trace_llm_chat_multi_modal(image_block, expected_image_url):\n    from llama_index.core.base.llms.types import TextBlock\n\n    llm = OpenAI()\n    message = ChatMessage(\n        role="user", blocks=[TextBlock(text="What is in the image?"), image_block]\n    )\n    llm.chat([message])\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    spans = traces[0].data.spans\n    assert len(spans) == 1\n    assert spans[0].span_type == SpanType.CHAT_MODEL\n    assert spans[0].model_name == llm.metadata.model_name\n\n\ndef test_trace_llm_chat_stream():\n    llm = OpenAI()\n    message = ChatMessage(role="system", content="Hello")\n\n    response_gen = llm.stream_chat([message], stream_options={"include_usage": True})\n    # No trace should be created until the generator is consumed\n    assert len(get_traces()) == 0\n    assert inspect.isgenerator(response_gen)\n\n    chunks = list(response_gen)\n    assert len(chunks) == 2\n    assert all(isinstance(c.message, ChatMessage) for c in chunks)\n    assert [c.message.content for c in chunks] == ["Hello", "Hello world"]\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    spans = traces[0].data.spans\n    assert len(spans) == 1\n    assert spans[0].name == "OpenAI.stream_chat"\n    assert spans[0].span_type == SpanType.CHAT_MODEL\n    assert spans[0].model_name == llm.metadata.model_name\n\n    content_json = _get_llm_input_content_json("Hello")\n    assert spans[0].inputs == {\n        "messages": [{"role": "system", **content_json, "additional_kwargs": {}}],\n        "kwargs": {"stream_options": {"include_usage": True}},\n    }\n    # `additional_kwargs` was broken until 0.1.30 release of llama-index-llms-openai\n    expected_kwargs = (\n        {"completion_tokens": 12, "prompt_tokens": 9, "total_tokens": 21}\n        if llama_oai_version >= Version("0.1.30")\n        else {}\n    )\n    output_content_json = _get_llm_input_content_json("Hello world")\n    assert spans[0].outputs == {\n        "message": {\n            "role": "assistant",\n            **output_content_json,\n            "additional_kwargs": {},\n        },\n        "raw": ANY,\n        "delta": " world",\n        "logprobs": None,\n        "additional_kwargs": expected_kwargs,\n    }\n\n    attr = spans[0].attributes\n    assert (\n        attr["usage"].items()\n        >= {\n            "prompt_tokens": 9,\n            "completion_tokens": 12,\n            "total_tokens": 21,\n            "completion_tokens_details": None,\n            "prompt_tokens_details": None,\n        }.items()\n    )\n    assert attr[SpanAttributeKey.CHAT_USAGE] == {\n        TokenUsageKey.INPUT_TOKENS: 9,\n        TokenUsageKey.OUTPUT_TOKENS: 12,\n        TokenUsageKey.TOTAL_TOKENS: 21,\n    }\n    assert attr["invocation_params"]["model_name"] == llm.metadata.model_name\n    assert attr["model_dict"]["model"] == llm.metadata.model_name\n    assert spans[0].model_name == llm.metadata.model_name\n    assert traces[0].info.token_usage == {\n        TokenUsageKey.INPUT_TOKENS: 9,\n        TokenUsageKey.OUTPUT_TOKENS: 12,\n        TokenUsageKey.TOTAL_TOKENS: 21,\n    }\n\n\n@pytest.mark.parametrize("is_stream", [True, False])\ndef test_trace_llm_error(monkeypatch, is_stream):\n    # Disable callback as it doesn\'t handle error response well\n    monkeypatch.setattr(Settings, "callback_manager", None)\n\n    llm = OpenAI(\n        api_base="http://localhost:1234/invalid/base",\n        timeout=1,\n        max_retries=0,\n    )\n    message = ChatMessage(role="system", content="Hello")\n\n    with pytest.raises(openai.APIConnectionError, match="Connection error."):  # noqa PT012\n        if is_stream:\n            next(llm.stream_chat([message]))\n        else:\n            llm.chat([message])\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.ERROR\n    spans = traces[0].data.spans\n    assert len(spans) == 1\n    assert spans[0].name == "OpenAI.stream_chat" if is_stream else "OpenAI.chat"\n    assert spans[0].span_type == SpanType.CHAT_MODEL\n    assert spans[0].inputs == {"messages": [message.model_dump()]}\n    assert spans[0].outputs is None\n    assert spans[0].model_name == llm.metadata.model_name\n    events = traces[0].data.spans[0].events\n    assert len(events) == 1\n    assert events[0].attributes["exception.message"] == "Connection error."\n\n\n@pytest.mark.parametrize("is_async", [True, False])\ndef test_trace_retriever(multi_index, is_async):\n    retriever = VectorIndexRetriever(multi_index, similarity_top_k=3)\n\n    if is_async:\n        retrieved = asyncio.run(retriever.aretrieve("apple"))\n    else:\n        retrieved = retriever.retrieve("apple")\n    assert len(retrieved) == 1\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    spans = traces[0].data.spans\n    assert len(spans) == 4\n    for i in range(1, 4):\n        assert spans[i].parent_id == spans[i - 1].span_id\n\n    assert spans[0].name.endswith("Retriever.aretrieve" if is_async else "Retriever.retrieve")\n    assert spans[0].span_type == SpanType.RETRIEVER\n    assert spans[0].inputs == {"str_or_query_bundle": "apple"}\n    assert len(spans[0].outputs) == 1\n\n    if Version(llama_index.core.__version__) >= Version("0.12.5"):\n        retrieved_text = retrieved[0].node.text\n    else:\n        retrieved_text = retrieved[0].text\n    assert spans[0].outputs[0]["page_content"] == retrieved_text\n\n    assert spans[1].name.startswith("VectorIndexRetriever")\n    assert spans[1].span_type == SpanType.RETRIEVER\n    assert spans[1].inputs["query_bundle"]["query_str"] == "apple"\n    assert spans[1].outputs == spans[0].outputs\n\n    assert "Embedding" in spans[2].name\n    assert spans[2].span_type == SpanType.EMBEDDING\n    assert spans[2].inputs == {"query": "apple"}\n    assert len(spans[2].outputs) == 1536  # embedding size\n    assert spans[2].attributes["model_name"] == Settings.embed_model.model_name\n    assert spans[2].model_name == Settings.embed_model.model_name\n\n    assert "Embedding" in spans[3].name\n    assert spans[3].span_type == SpanType.EMBEDDING\n    assert spans[3].inputs == {"query": "apple"}\n    assert len(spans[3].outputs) == 1536  # embedding size\n    assert spans[3].attributes["model_name"] == Settings.embed_model.model_name\n    assert spans[3].model_name == Settings.embed_model.model_name\n\n\n@pytest.mark.parametrize("is_stream", [False, True])\n@pytest.mark.parametrize("is_async", [False, True])\ndef test_trace_query_engine(multi_index, is_stream, is_async):\n    if is_stream and is_async:\n        pytest.skip("Async stream is not supported yet")\n\n    engine = multi_index.as_query_engine(streaming=is_stream)\n\n    if is_stream:\n        response = engine.query("Hello")\n        assert isinstance(response, StreamingResponse)\n        response = "".join(response.response_gen)\n        assert response == "Hello world"\n    else:\n        response = asyncio.run(engine.aquery("Hello")) if is_async else engine.query("Hello")\n        assert response.response.startswith(\'[{"role": "system", "content": "You are an\')\n        response = asdict(response)\n        if Version(llama_index.core.__version__) > Version("0.10.68"):\n            response["source_nodes"] = [n.dict() for n in response["source_nodes"]]\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    # Async methods have "a" prefix\n    prefix = "a" if is_async else ""\n\n    # Validate span attributes for some key spans\n    spans = traces[0].data.spans\n    assert spans[0].name.endswith(f"QueryEngine.{prefix}query")\n    assert spans[0].span_type == SpanType.CHAIN\n    assert spans[0].inputs == {"str_or_query_bundle": "Hello"}\n    assert spans[0].outputs == response\n\n\n@pytest.mark.skipif(llama_core_version >= Version("0.13.0"), reason="OpenAIAgent is removed")\ndef test_trace_agent():\n    from llama_index.agent.openai import OpenAIAgent\n\n    # Mock LLM to return deterministic responses and let the agent use a tool\n    class MockLLMForAgent(OpenAI, extra="allow"):\n        def __init__(self, *args, **kwargs):\n            super().__init__(*args, **kwargs)\n            self._mock_response = iter([\n                ChatResponse(\n                    message=ChatMessage(\n                        role="assistant",\n                        content=None,\n                        additional_kwargs={\n                            "tool_calls": [\n                                ChatCompletionMessageToolCall(\n                                    id="test",\n                                    function={\n                                        "name": "add",\n                                        "arguments": \'{"a": 1, "b": 2}\',\n                                    },\n                                    type="function",\n                                )\n                            ]\n                        },\n                    )\n                ),\n                ChatResponse(\n                    message=ChatMessage(\n                        role="assistant",\n                        content="The result is 3",\n                    )\n                ),\n            ])\n\n        @llm_chat_callback()\n        def chat(self, *args, **kwargs):\n            return next(self._mock_response)\n\n    def add(a: int, b: int) -> int:\n        """Add two integers and returns the result integer"""\n        return a + b\n\n    add_tool = FunctionTool.from_defaults(fn=add)\n\n    llm = MockLLMForAgent()\n    agent = OpenAIAgent.from_tools([add_tool], llm=llm)\n    response = agent.chat("What is 1 + 2?").response\n\n    assert response == "The result is 3"\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    spans = traces[0].data.spans\n    name_to_span = {span.name: span for span in spans}\n    tool_span = name_to_span["FunctionTool.call"]\n    assert tool_span.span_type == SpanType.TOOL\n    assert tool_span.inputs == {"kwargs": {"a": 1, "b": 2}}\n    assert tool_span.outputs.get("raw_output") == 3\n    assert tool_span.attributes["name"] == "add"\n    assert tool_span.attributes["description"] is not None\n    assert tool_span.attributes["parameters"] is not None\n\n    # Validate the chat messages and tool calls are captured in LLM span attributes\n    llm_spans = [s for s in spans if s.span_type == SpanType.CHAT_MODEL]\n    assert len(llm_spans) == 2\n    assert llm_spans[0].get_attribute(SpanAttributeKey.CHAT_TOOLS) == [\n        {\n            "function": {\n                "name": "add",\n                "description": (\n                    "add(a: int, b: int) -> int\\nAdd two integers and returns the result integer"\n                ),\n                "parameters": {\n                    "properties": {\n                        "a": {\n                            "title": "A",\n                            "type": "integer",\n                        },\n                        "b": {\n                            "title": "B",\n                            "type": "integer",\n                        },\n                    },\n                    "required": ["a", "b"],\n                    "type": "object",\n                },\n            },\n            "type": "function",\n        }\n    ]\n    assert llm_spans[0].model_name == llm.metadata.model_name\n    assert llm_spans[1].model_name == llm.metadata.model_name\n\n\n@pytest.mark.parametrize("is_stream", [False, True])\n@pytest.mark.parametrize("is_async", [False, True])\ndef test_trace_chat_engine(multi_index, is_stream, is_async):\n    if is_stream:\n        if is_async:\n            pytest.skip("Async stream is not supported yet")\n\n        # Skip streaming test for llama-index <0.13 due to race condition with OpenAIAgent\n        # where child spans are created after root span completes, causing incomplete traces\n        if llama_core_version < Version("0.13.0"):\n            pytest.skip("Streaming chat engine test is flaky for llama-index <0.13")\n\n    engine = multi_index.as_chat_engine()\n\n    if is_stream:\n        response_gen = engine.stream_chat("Hello").response_gen\n        response = "".join(response_gen)\n        assert response == "Hello world"\n    else:\n        response = asyncio.run(engine.achat("Hello")) if is_async else engine.chat("Hello")\n        # a default prompt is added in llama-index 0.13.0\n        # https://github.com/run-llama/llama_index/blob/1e02c7a2324838f7bd5a52c811d35c30dc6a6bd2/llama-index-core/llama_index/core/chat_engine/condense_plus_context.py#L40\n        assert \'{"role": "user", "content": "Hello"}\' in response.response\n\n    # Since chat engine is a complex agent-based system, it is challenging to strictly\n    # validate the trace structure and attributes. The detailed validation is done in\n    # other tests for individual components.\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n    root_span = traces[0].data.spans[0]\n    assert root_span.inputs == {"message": "Hello"}\n\n\n@skip_when_testing_trace_sdk\ndef test_tracer_handle_tracking_uri_update(tmp_path):\n    OpenAI().complete("Hello")\n    assert len(get_traces()) == 1\n\n    # Set different tracking URI and initialize the tracer\n    with _use_tracking_uri(tmp_path / "dummy"):\n        assert len(get_traces()) == 0\n\n        # The new trace will be logged to the updated tracking URI\n        OpenAI().complete("Hello")\n        assert len(get_traces()) == 1\n\n\n# Utility functions to set/get a value in the workflow context, handling API differences:\n#\n# - For llama-index-workflows < 2.0: ctx.set(key, value) and ctx.get(key)\n# - For llama-index-workflows >= 2.0: ctx.store.set(key, value) and ctx.store.get(key)\n#\n# See: https://github.com/run-llama/workflows-py/pull/55\nasync def context_set(ctx: Context, key: str, value: Any) -> None:\n    if llama_workflows_version and llama_workflows_version.major >= 2:\n        await ctx.store.set(key, value)\n    else:\n        await ctx.set(key, value)\n\n\nasync def context_get(ctx: Context, key: str) -> Any:\n    if llama_workflows_version and llama_workflows_version.major >= 2:\n        return await ctx.store.get(key)\n    else:\n        return await ctx.get(key)\n\n\n@pytest.mark.skipif(\n    llama_core_version < Version("0.11.0"),\n    reason="Workflow was introduced in 0.11.0",\n)\n@pytest.mark.asyncio\nasync def test_tracer_simple_workflow():\n    from llama_index.core.workflow import StartEvent, StopEvent, Workflow, step\n\n    class MyWorkflow(Workflow):\n        @step\n        async def my_step(self, ev: StartEvent) -> StopEvent:\n            return StopEvent(result="Hi, world!")\n\n    w = MyWorkflow(timeout=10, verbose=False)\n    await w.run()\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n    assert all(s.status.status_code == SpanStatusCode.OK for s in traces[0].data.spans)\n\n\n@pytest.mark.skipif(\n    llama_core_version < Version("0.11.0"),\n    reason="Workflow was introduced in 0.11.0",\n)\n@pytest.mark.asyncio\nasync def test_tracer_parallel_workflow():\n    from llama_index.core.workflow import (\n        Context,\n        Event,\n        StartEvent,\n        StopEvent,\n        Workflow,\n        step,\n    )\n\n    class ProcessEvent(Event):\n        data: str\n\n    class ResultEvent(Event):\n        result: str\n\n    class ParallelWorkflow(Workflow):\n        @step\n        async def start(self, ctx: Context, ev: StartEvent) -> ProcessEvent:\n            await context_set(ctx, "num_to_collect", len(ev.inputs))\n            for item in ev.inputs:\n                ctx.send_event(ProcessEvent(data=item))\n            return None\n\n        @step(num_workers=3)\n        async def process_data(self, ev: ProcessEvent) -> ResultEvent:\n            # Simulate some time-consuming processing\n            await asyncio.sleep(random.randint(1, 2))\n            return ResultEvent(result=ev.data)\n\n        @step\n        async def combine_results(self, ctx: Context, ev: ResultEvent) -> StopEvent:\n            num_to_collect = await context_get(ctx, "num_to_collect")\n            results = ctx.collect_events(ev, [ResultEvent] * num_to_collect)\n            if results is None:\n                return None\n\n            combined_result = ", ".join(sorted([event.result for event in results]))\n            return StopEvent(result=combined_result)\n\n    w = ParallelWorkflow()\n    result = await w.run(inputs=["apple", "grape", "orange", "banana"])\n    assert result == "apple, banana, grape, orange"\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n    for s in traces[0].data.spans:\n        assert s.status.status_code == SpanStatusCode.OK\n\n    root_span = traces[0].data.spans[0]\n    expected_inputs = {"kwargs": {"inputs": ["apple", "grape", "orange", "banana"]}}\n    # assert that the inputs are a superset of the expected inputs.\n    # this is to make the test resilient to framework changes which may add additional inputs.\n    assert all(root_span.inputs.get(k) == v for k, v in expected_inputs.items())\n    # in llama-index < 0.14, outputs are a string\n    if isinstance(root_span.outputs, str):\n        assert root_span.outputs == "apple, banana, grape, orange"\n    else:\n        assert root_span.outputs["result"] == "apple, banana, grape, orange"\n\n\n@pytest.mark.skipif(\n    llama_core_version < Version("0.11.0"),\n    reason="Workflow was introduced in 0.11.0",\n)\n@pytest.mark.asyncio\nasync def test_tracer_parallel_workflow_with_custom_spans():\n    from llama_index.core.workflow import (\n        Context,\n        Event,\n        StartEvent,\n        StopEvent,\n        Workflow,\n        step,\n    )\n\n    class ProcessEvent(Event):\n        data: str\n\n    class ResultEvent(Event):\n        result: str\n\n    class ParallelWorkflow(Workflow):\n        @step\n        async def start(self, ctx: Context, ev: StartEvent) -> ProcessEvent:\n            await context_set(ctx, "num_to_collect", len(ev.inputs))\n            for item in ev.inputs:\n                ctx.send_event(ProcessEvent(data=item))\n            return None\n\n        @step(num_workers=3)\n        async def process_data(self, ev: ProcessEvent) -> ResultEvent:\n            # Simulate some time-consuming processing\n            await asyncio.sleep(random.randint(1, 2))\n            with mlflow.start_span(name="custom_inner_span_worker"):\n                pass\n            return ResultEvent(result=ev.data)\n\n        @step\n        async def combine_results(self, ctx: Context, ev: ResultEvent) -> StopEvent:\n            num_to_collect = await context_get(ctx, "num_to_collect")\n            results = ctx.collect_events(ev, [ResultEvent] * num_to_collect)\n            if results is None:\n                return None\n\n            with mlflow.start_span(name="custom_inner_result_span") as span:\n                span.set_inputs(results)\n                combined_result = ", ".join(sorted([event.result for event in results]))\n                span.set_outputs(combined_result)\n            return StopEvent(result=combined_result)\n\n    w = ParallelWorkflow()\n    inputs = ["apple", "grape", "orange", "banana"]\n\n    result = await w.run(inputs=inputs)\n    assert result == "apple, banana, grape, orange"\n\n    traces = get_traces()\n    assert len(traces) == 1\n    assert traces[0].info.status == TraceStatus.OK\n\n    spans = traces[0].data.spans\n    assert all(s.status.status_code == SpanStatusCode.OK for s in spans)\n\n    workflow_span = spans[0]\n    assert all(workflow_span.inputs.get(k) == v for k, v in {"kwargs": {"inputs": inputs}}.items())\n    if isinstance(workflow_span.outputs, str):\n        assert workflow_span.outputs == result\n    else:\n        assert workflow_span.outputs["result"] == result\n\n    inner_worker_spans = [s for s in spans if s.name.startswith("custom_inner_span_worker")]\n    assert len(inner_worker_spans) == len(inputs)\n\n    inner_result_span = next(s for s in spans if s.name == "custom_inner_result_span")\n    assert inner_result_span.inputs is not None\n    assert inner_result_span.outputs == result\n\n\n@pytest.mark.asyncio\n@pytest.mark.parametrize("should_close", [True, False])\nasync def test_stream_resolver_with_async_generator(should_close):\n    async def async_generator():\n        yield "chunk1"\n        yield "chunk2"\n\n    resolver = StreamResolver()\n    tracer = _get_tracer(__name__)\n\n    agen = async_generator()\n    if should_close:\n        async for _ in agen:\n            pass\n\n    with tracer.start_as_current_span("test_closed_async") as otel_span:\n        from mlflow.entities.span import LiveSpan\n\n        trace_id = f"{otel_span.context.trace_id:032x}"\n        span = LiveSpan(otel_span=otel_span, trace_id=trace_id)\n\n        # Should detect that the generator is closed and return False\n        result = resolver.register_stream_span(span, agen)\n        assert result == (not should_close)\n',
        }
